module pulse_detect (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

localparam STATE_IDLE = 2'b00;
localparam STATE_RISE = 2'b01;
localparam STATE_FALL = 2'b10;

reg [1:0] state;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        state <= STATE_IDLE;
        data_out <= 1'b0;
    end
    else begin
        case (state)
            STATE_IDLE: begin
                if (data_in == 1'b1) begin
                    state <= STATE_RISE;
                end
                else begin
                    state <= STATE_IDLE;
                end
                data_out <= 1'b0;
            end
            STATE_RISE: begin
                if (data_in == 1'b1) begin
                    state <= STATE_FALL;
                end
                else begin
                    state <= STATE_IDLE;
                end
                data_out <= 1'b0;
            end
            STATE_FALL: begin
                if (data_in == 1'b0) begin
                    state <= STATE_IDLE;
                    data_out <= 1'b1;
                end
                else begin
                    state <= STATE_FALL;
                end
                data_out <= 1'b0;
            end
            default: begin
                state <= STATE_IDLE;
                data_out <= 1'b0;
            end
    endcase
end

end // Auto-repaired
endmodule
